from flask import Flask, request, jsonify
import yaml

app = Flask(__name__)

@app.route('/yaml', methods=['POST'])
def yaml_load():
    data = request.get_data()
    try:
        parsed = yaml.safe_load(data)
        return jsonify(parsed)
    except Exception as e:
